#include<cstdio>
#include<cstring>
using namespace std;
int t;
int in(){
    int k=0,f=1;
    char c=getchar_unlocked();
    while(c<'0'||c>'9'){
        if(c=='-')f=-1;
        c=getchar_unlocked();
    }
    while(c>='0'&&c<='9')k=k*10+c-'0',c=getchar_unlocked();
    return k*f;
}
unsigned long long h[1000005],Pow[1000005];
unsigned long long qp(unsigned long long b){
	if(Pow[b])return Pow[b];
	unsigned long long ans=1,a=131;
	while(b){
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return Pow[b]=ans;
}
int main(){
    char ch;
	for(int i=1;;i++){
		ch=getchar();
		if(ch=='\n')break;
		h[i]=h[i-1]*131+ch-'a';
	}
    t=in();
    int l1,r1,l2,r2;
    while(t--){
        l1=in(),r1=in(),l2=in(),r2=in();
        if(h[r1]-h[l1-1]*qp(r1-l1+1)==h[r2]-h[l2-1]*qp(r2-l2+1)){
			putchar('Y');
			putchar('e');
			putchar('s');
			putchar('\n');
		}else{
			putchar('N');
			putchar('o');
			putchar('\n');
		}
    }
    return 0;
}
